class Solution:
    def firstCompleteIndex(self, arr, mat):
        m = len(mat)
        n = len(mat[0])
        pos = {}
        for r in range(m):
            for c in range(n):
                pos[mat[r][c]] = (r, c)
        painted = [[False] * n for _ in range(m)]
        for i, v in enumerate(arr):
            r, c = pos[v]
            painted[r][c] = True
            if all(painted[r][cc] for cc in range(n)) or all(painted[rr][c] for rr in range(m)):
                return i
        return -1

