var firstCompleteIndex = function(arr, mat) {
    const m = mat.length;
    const n = mat[0].length;
    const posRow = new Map();
    const posCol = new Map();
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            posRow.set(mat[r][c], r);
            posCol.set(mat[r][c], c);
        }
    }
    const rowCount = new Array(m).fill(0);
    const colCount = new Array(n).fill(0);
    for (let i = 0; i < arr.length; i++) {
        const v = arr[i];
        const r = posRow.get(v);
        const c = posCol.get(v);
        rowCount[r]++;
        colCount[c]++;
        if (rowCount[r] === n || colCount[c] === m) {
            return i;
        }
    }
    return -1;
};
